import React, { useState } from 'react';
import { ShieldExclamationIcon } from '@heroicons/react/24/solid';

const SOSButton = () => {
  const [active, setActive] = useState(false);

  const handleSOS = () => {
    setActive(true);
    alert("SOS ALERT SENT! Real-time location is being shared with emergency contacts.");
    // In a real app, you'd call your backend API here
    setTimeout(() => setActive(false), 3000);
  };

  return (
    <button
      onClick={handleSOS}
      className={`fixed bottom-8 right-8 z-50 flex items-center justify-center 
        w-20 h-20 rounded-full shadow-2xl transition-all duration-300 transform 
        hover:scale-110 active:scale-95
        ${active ? 'bg-orange-600 animate-ping' : 'bg-red-600 hover:bg-red-700'}`}
    >
      <div className="absolute inset-0 rounded-full bg-red-500 opacity-20 animate-pulse"></div>
      <ShieldExclamationIcon className="h-10 w-10 text-white relative z-10" />
      <span className="absolute -top-10 right-0 bg-red-600 text-white text-xs font-bold px-2 py-1 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity">
        EMERGENCY SOS
      </span>
    </button>
  );
};

export default SOSButton;
